export declare const QUERY_SCHEMAS = "\nSELECT schema_name\nFROM information_schema.schemata\nWHERE schema_name NOT IN ('pg_catalog', 'information_schema', 'pg_toast', 'pg_temp_1', 'pg_toast_temp_1')\n  AND schema_name NOT LIKE 'pg_%'\nORDER BY schema_name;\n";
export declare const QUERY_TABLES = "\nSELECT table_name, table_schema AS schema\nFROM information_schema.tables\nWHERE table_type = 'BASE TABLE'\n  AND table_schema = $1\nORDER BY table_name;\n";
export declare const QUERY_VIEWS = "\nSELECT table_name AS view_name, table_schema AS schema\nFROM information_schema.views\nWHERE table_schema = $1\nORDER BY table_name;\n";
export declare const QUERY_FUNCTIONS = "\nSELECT\n  routine_name AS function_name,\n  routine_schema AS schema,\n  data_type AS return_type\nFROM information_schema.routines\nWHERE routine_type = 'FUNCTION'\n  AND routine_schema = $1\nORDER BY routine_name;\n";
export declare const QUERY_TRIGGERS = "\nSELECT\n  trigger_name,\n  event_object_table AS table_name,\n  string_agg(event_manipulation, ', ') AS event\nFROM information_schema.triggers\nGROUP BY trigger_name, event_object_table\nORDER BY trigger_name;\n";
export declare const QUERY_ENUMS = "\nSELECT\n  t.typname AS type_name,\n  n.nspname AS schema,\n  array_agg(e.enumlabel ORDER BY e.enumsortorder) AS values\nFROM pg_type t\nJOIN pg_namespace n ON n.oid = t.typnamespace\nJOIN pg_enum e ON e.enumtypid = t.oid\nWHERE t.typtype = 'e'\nGROUP BY t.typname, n.nspname\nORDER BY n.nspname, t.typname;\n";
export declare const QUERY_INDEXES = "\nSELECT\n  i.relname AS index_name,\n  t.relname AS table_name,\n  n.nspname AS schema\nFROM pg_index ix\nJOIN pg_class i ON i.oid = ix.indexrelid\nJOIN pg_class t ON t.oid = ix.indrelid\nJOIN pg_namespace n ON n.oid = t.relnamespace\nWHERE n.nspname NOT IN ('pg_catalog', 'information_schema', 'pg_toast')\nORDER BY n.nspname, t.relname, i.relname;\n";
export declare const QUERY_ROLES = "\nSELECT rolname AS role_name\nFROM pg_roles\nWHERE rolname NOT LIKE 'pg_%'\nORDER BY rolname;\n";
export declare const QUERY_POLICIES = "\nSELECT\n  pol.polname AS policy_name,\n  cls.relname AS table_name,\n  nsp.nspname AS schema\nFROM pg_policy pol\nJOIN pg_class cls ON cls.oid = pol.polrelid\nJOIN pg_namespace nsp ON nsp.oid = cls.relnamespace\nORDER BY nsp.nspname, cls.relname, pol.polname;\n";
export declare const QUERY_STORAGE_BUCKETS = "\nSELECT id, name, public FROM storage.buckets ORDER BY name;\n";
